   224→            kerberosName = KerberosName.parse(servicePrincipal);
   225→        } catch (IllegalArgumentException e) {
   226→            throw new KafkaException("Principal has name with unexpected format " + servicePrincipal);
   227→        }
   228→        final String servicePrincipalName = kerberosName.serviceName();
   229→        final String serviceHostname = kerberosName.hostName();
   230→
   231→        LOG.debug("Creating SaslServer for {} with mechanism {}", kerberosName, saslMechanism);
   232→
   233→        try {
   234→            return SecurityManagerCompatibility.get().callAs(subject, () ->
   235→                    Sasl.createSaslServer(saslMechanism, servicePrincipalName, serviceHostname, configs, saslServerCallbackHandler));
   236→        } catch (CompletionException e) {
   237→            throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication", e.getCause());
   238→        }
   239→    }
